-    // Performs equivalent check of std::fabs(lhs - rhs) <= margin
-    // But without the subtraction to allow for INFINITY in comparison
     bool WithinAbsMatcher::match(double const& matchee) const {
-        return (matchee + m_margin >= m_target) && (m_target + m_margin >= matchee);
+        // For subnormal values near zero the add-margin approach can produce
+        // false positives: when m_margin is larger than subnormal magnitudes,
+        // the addition loses the relative scale information.  Using
+        // std::fabs(matchee - m_target) gives the exact IEEE-754 absolute
+        // difference for all finite (including subnormal) values.
+        // We fall back to the add-margin form only for infinities, because
+        // INF - INF = NaN would make fabs-subtraction undefined.
+        if ( !std::isinf( matchee ) && !std::isinf( m_target ) ) {
+            return std::fabs( matchee - m_target ) <= m_margin;
+        }
+        return ( matchee + m_margin >= m_target ) &&
+               ( m_target + m_margin >= matchee );
     }

